parameters.jsCode:
// Extrae la ficha del texto del LLM (formato OpenAI/OpenRouter).
let raw = $json.choices?.[0]?.message?.content ?? $json.choices?.[0]?.text ?? '';
raw = String(raw).trim().replace(/^```(json)?/i, '').replace(/```$/, '').trim();
const i = raw.indexOf('{'), j = raw.lastIndexOf('}');
if (i < 0 || j < 0) throw new Error('El LLM no devolvio JSON: ' + raw.slice(0, 200));
const ficha = JSON.parse(raw.slice(i, j + 1));
return [{ json: { ficha } }];

// Genera el modelo .s3d invocando el CLI determinista (ya probado).
// REQUISITOS en n8n self-hosted (local):
//   - variable de entorno PORTICO_DIR = ruta absoluta del repo structweb3d
//   - NODE_FUNCTION_ALLOW_BUILTIN=child_process,path  (o '*')
const { execFileSync } = require('child_process');
const path = require('path');
const dir = process.env.PORTICO_DIR || 'C:/Workspace/analisis_estructural_dinamico';
const cli = path.join(dir, 'asistente', 'generar_cli.mjs');
const ficha = $json.ficha;
let out;
try {
  out = execFileSync('node', [cli], { input: JSON.stringify(ficha), encoding: 'utf8', maxBuffer: 50 * 1024 * 1024 });
} catch (e) {
  throw new Error('generador: ' + (e.stderr || e.message));
}
const modelo = JSON.parse(out);
return [{ json: { ficha, resumen: modelo._generado?.resumen, modelo } }];
